+    private static boolean looksLikeDrillable(byte[] bytes) {
+        int len = bytes.length;
+        if (len < 2) {
+            return false;
+        }
+        int b1 = bytes[1] & 0xff;
+        return switch (b1) {
+            case 0x80 -> true;
+            case 0x81 -> bytes.length >= 3 && (bytes[2] & 0xff) == len - 3;
+            case 0x82 -> bytes.length >= 4
+                    && (((bytes[2] & 0xff) << 8) | (bytes[3] & 0xff)) == len - 4;
+            case 0x83, 0x84 -> false;
+            default -> b1 == len - 2;
+        };
+    }
